sql:
SELECT AVG(child_mort_rate) AS average_child_mortality_rate
FROM child_mortality_rates
WHERE year = 2020;

SELECT AVG(life_expectancy) AS average_life_expectancy
FROM life_expectancies
WHERE year = 2020;

SELECT year, AVG(export_value) AS average_export_value
FROM exports
GROUP BY year;

external_knowledge:
- 'recent' refers to the last five years of data available;
- 'highest 10% of mortality rates' means the countries that have the highest 10% of average child mortality rates among all countries;
- 'from highest to lowest rates' ensures that the results are ordered, where the highest mortality rates are shown first.

sql:
SELECT AVG(inflation_rate) AS average_inflation_rate
FROM inflation_rates
WHERE year = 2020;

SELECT country_name, iso_code, region, population, area, capital, currency
FROM countries
ORDER BY population DESC;

SELECT gdpp
FROM gdp_per_capita
WHERE country_id = 1 AND year = 2020;

SELECT AVG(income_level) AS average_income_level
FROM income_levels
WHERE year = 2020;

